		&lt;script id=&quot;MathJax-Element-7&quot; type=&quot;math/mml&quot;&gt;&lt;math display=&quot;block&quot; xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&quot;normal&quot;&gt;°&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mrow&gt;&lt;mo fence=&quot;true&quot;&gt;(&lt;/mo&gt;&lt;mfrac&gt;&lt;mn&gt;5&lt;/mn&gt;&lt;mn&gt;9&lt;/mn&gt;&lt;/mfrac&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;mo stretchy=&quot;false&quot;&gt;(&lt;/mo&gt;&lt;mn&gt;77&lt;/mn&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;32&lt;/mn&gt;&lt;mo stretchy=&quot;false&quot;&gt;)&lt;/mo&gt;&lt;mo fence=&quot;true&quot;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mrow&gt;&lt;mo fence=&quot;true&quot;&gt;(&lt;/mo&gt;&lt;mfrac&gt;&lt;mn&gt;5&lt;/mn&gt;&lt;mn&gt;9&lt;/mn&gt;&lt;/mfrac&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;mn&gt;45&lt;/mn&gt;&lt;mo fence=&quot;true&quot;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;25&lt;/mn&gt;&lt;mi mathvariant=&quot;normal&quot;&gt;°&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt; °C = \left( \frac{5}{9} \times (77 - 32) \right) = \left( \frac{5}{9} \times 45 \right) = 25°C&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt;
		&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;
		&lt;span class=&quot;katex-display&quot;&gt;&lt;span class=&quot;katex&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt; &lt;script id=&quot;MathJax-Element-4&quot; type=&quot;math/mml&quot;&gt;&lt;math display=&quot;block&quot; xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&quot;normal&quot;&gt;°&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mrow&gt;&lt;mo fence=&quot;true&quot;&gt;(&lt;/mo&gt;&lt;mfrac&gt;&lt;mn&gt;5&lt;/mn&gt;&lt;mn&gt;9&lt;/mn&gt;&lt;/mfrac&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;mo stretchy=&quot;false&quot;&gt;(&lt;/mo&gt;&lt;mn&gt;77&lt;/mn&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;32&lt;/mn&gt;&lt;mo stretchy=&quot;false&quot;&gt;)&lt;/mo&gt;&lt;mo fence=&quot;true&quot;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mrow&gt;&lt;mo fence=&quot;true&quot;&gt;(&lt;/mo&gt;&lt;mfrac&gt;&lt;mn&gt;5&lt;/mn&gt;&lt;mn&gt;9&lt;/mn&gt;&lt;/mfrac&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;mn&gt;45&lt;/mn&gt;&lt;mo fence=&quot;true&quot;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;25&lt;/mn&gt;&lt;mi mathvariant=&quot;normal&quot;&gt;°&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt;°C = \left( \frac{5}{9} \times (77 - 32) \right) = \left( \frac{5}{9} \times 45 \right) = 25°C&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt; &lt;/span&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&amp;deg;&lt;/span&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;C&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;minner&quot;&gt;&lt;span class=&quot;mopen delimcenter&quot;&gt;&lt;span class=&quot;delimsizing size3&quot;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mfrac&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord&quot;&gt;9&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord&quot;&gt;5&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mbin&quot;&gt;&amp;times;&lt;/span&gt;&lt;span class=&quot;mopen&quot;&gt;(&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;77&lt;/span&gt;&lt;span class=&quot;mbin&quot;&gt;&amp;minus;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;32&lt;/span&gt;&lt;span class=&quot;mclose&quot;&gt;)&lt;/span&gt;&lt;span class=&quot;mclose delimcenter&quot;&gt;&lt;span class=&quot;delimsizing size3&quot;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;minner&quot;&gt;&lt;span class=&quot;mopen delimcenter&quot;&gt;&lt;span class=&quot;delimsizing size3&quot;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mfrac&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord&quot;&gt;9&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord&quot;&gt;5&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mbin&quot;&gt;&amp;times;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;45&lt;/span&gt;&lt;span class=&quot;mclose delimcenter&quot;&gt;&lt;span class=&quot;delimsizing size3&quot;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;25&amp;deg;&lt;/span&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;830&quot; data-is-last-node=&quot;&quot; data-is-only-node=&quot;&quot; data-start=&quot;741&quot;&gt;Thus, the correct formula is:
	&lt;ul&gt;
		&lt;li data-end=&quot;830&quot; data-is-last-node=&quot;&quot; data-is-only-node=&quot;&quot; data-start=&quot;741&quot;&gt;&amp;nbsp;&lt;strong data-end=&quot;799&quot; data-start=&quot;775&quot;&gt;&amp;deg;F = (9/5 &amp;times; &amp;deg;C) + 32&lt;/strong&gt;&lt;/li&gt;
		&lt;li data-end=&quot;830&quot; data-is-last-node=&quot;&quot; data-is-only-node=&quot;&quot; data-start=&quot;741&quot;&gt;&amp;nbsp;&lt;strong data-end=&quot;830&quot; data-is-last-node=&quot;&quot; data-start=&quot;804&quot;&gt;&amp;deg;C = (5/9) &amp;times; (&amp;deg;F - 32)&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;-273.15&amp;ordm;C&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Absolute zero temperature is defined as 0 Kelvin (K).&lt;/li&gt;
	&lt;li&gt;In Celsius (&amp;ordm;C), absolute zero is equivalent to -273.15&amp;ordm;C.&lt;/li&gt;
	&lt;li&gt;Absolute zero is the lowest possible temperature where all molecular motion ceases.&lt;/li&gt;
	&lt;li&gt;This temperature is theoretically and practically unattainable.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Kelvin Scale&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The Kelvin scale is an absolute temperature scale used in science.&lt;/li&gt;
		&lt;li&gt;It starts at absolute zero and uses the same increment as the Celsius scale.&lt;/li&gt;
		&lt;li&gt;0 K is equal to -273.15&amp;ordm;C, and 273.15 K is equal to 0&amp;ordm;C.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Thermodynamics&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Thermodynamics is the branch of physics that deals with heat, work, and temperature.&lt;/li&gt;
		&lt;li&gt;The third law of thermodynamics states that as temperature approaches absolute zero, the entropy of a system approaches a constant minimum.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Entropy&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Entropy is a measure of disorder or randomness in a system.&lt;/li&gt;
		&lt;li&gt;At absolute zero, the entropy of a perfectly crystalline substance is zero.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Practical Limitations&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Absolute zero cannot be reached experimentally; it is an asymptotic limit.&lt;/li&gt;
		&lt;li&gt;Scientists have achieved temperatures within a fraction of a degree above absolute zero.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&lt;u&gt;&lt;strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;Echo.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Echo&amp;nbsp;&lt;/span&gt;sound produces due to reflection of sound&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;that arrives at the listener with a delay after the direct sound.&lt;/li&gt;
	&lt;li&gt;There must be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;at least&amp;nbsp;&lt;u&gt;0.1s&lt;/u&gt;&amp;nbsp;&lt;/span&gt;to hear a distinct echo&amp;nbsp;of the time interval between the original sound and the reflected one.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;minimum distance&amp;nbsp;&lt;/span&gt;of the obstacle from the source of sound for hearing distinct echoes&amp;nbsp;must be&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;17.2 m&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;This distance changes with the temperature of the air. Echoes heard more than once due to successive or multiple reflections.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;Sound is caused by the&amp;nbsp;&lt;/span&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;reflection of sound waves&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;from the surface to the observer.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;Detecting obstacles and barriers is done through echolocation by&amp;nbsp;&lt;/span&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;birds, dolphins, and fishermen.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Sound:&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Vibrations&lt;/span&gt;&amp;nbsp;traveling through&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;air or another medium&lt;/span&gt;&amp;nbsp;can be heard by humans or animals.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Reverberation:&lt;/span&gt;&amp;nbsp;When the&amp;nbsp;s&lt;span style=&quot;font-weight: 700;&quot;&gt;ound persists by repeated reflection&lt;/span&gt;&amp;nbsp;until it is no longer audible in an empty hall. To reduce this normal we use&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;soundproofing material&lt;/span&gt;&amp;nbsp;like&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rough plastic or draperies&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&lt;u&gt;&lt;strong&gt;&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;Heterotrophs&amp;#39; survival depends directly or indirectly on autotrophs.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&lt;strong&gt; correct statement is H&lt;/strong&gt;eterotrophs&amp;#39; survival depends directly or indirectly on autotrophs.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Autotrophs&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;These are organisms (like plants, algae, and some bacteria) that can produce their own food through processes like &lt;strong&gt;photosynthesis&lt;/strong&gt; or &lt;strong&gt;chemosynthesis&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;They are the primary producers in the ecosystem, forming the base of the food chain by converting sunlight or inorganic compounds into energy-rich organic compounds.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Heterotrophs&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;These are organisms (like animals, fungi, and most bacteria)&lt;strong&gt; that cannot produce their own food. Instead, they rely on consuming other organisms&amp;mdash;either autotrophs directly (herbivores) or other heterotrophs (carnivores, omnivores).&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;Herbivores feed directly on autotrophs (e.g., cows eating grass, deer feeding on plants).&lt;/li&gt;
	&lt;li&gt;Some organisms like fungi also decompose dead autotrophs to derive nutrients.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Animals are autotrophs:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;This is false, animals are heterotrophs as they cannot produce their own food.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Autotrophs&amp;#39; survival depends directly on heterotrophs:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;This is incorrect, autotrophs can survive independently as they can produce their own food.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;All bacteria are autotrophs:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;This is not true, while some bacteria are autotrophic, many are heterotrophic&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;b&gt;&lt;u&gt;Pupil&lt;/u&gt;&lt;/b&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The iris is a thin, circular structure in the eye responsible for controlling the diameter and size of the pupil.&lt;/li&gt;
	&lt;li&gt;It regulates the amount of light entering the eye by adjusting the pupil size, which is essential for optimal vision.&lt;/li&gt;
	&lt;li&gt;The iris contains muscles that contract and expand to adjust the pupil size in response to varying light conditions.&lt;/li&gt;
	&lt;li&gt;The color of the iris is what gives the eye its color, varying from blue, green, brown, etc.&lt;/li&gt;
	&lt;li&gt;The process by which the iris adjusts the pupil size is known as the pupillary light reflex.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Retina&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The retina is the light-sensitive layer at the back of the eye that converts light into electrical signals.&lt;/li&gt;
		&lt;li&gt;It contains photoreceptor cells called rods and cones that detect light intensity and color.&lt;/li&gt;
		&lt;li&gt;The retina plays a crucial role in forming visual images and transmitting them to the brain via the optic nerve.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Cornea&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The cornea is the transparent, dome-shaped front layer of the eye that covers the iris, pupil, and anterior chamber.&lt;/li&gt;
		&lt;li&gt;It plays a key role in focusing light onto the retina, contributing to the eye&amp;#39;s overall refractive power.&lt;/li&gt;
		&lt;li&gt;The cornea is avascular, meaning it has no blood vessels, and receives nutrients from tears and aqueous humor.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Pupil&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The pupil is the black circular opening in the center of the iris that allows light to enter the eye.&lt;/li&gt;
		&lt;li&gt;Its size is regulated by the iris muscles, contracting in bright light and dilating in low light to control light intake.&lt;/li&gt;
		&lt;li&gt;The pupil&amp;#39;s adjustment is an essential part of the eye&amp;#39;s response to different lighting conditions.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Protein Deficiency&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Protein deficiency can lead to stunted growth in children as protein is essential for the development and repair of body tissues.&lt;/li&gt;
	&lt;li&gt;Discoloured hair, particularly a reddish-orange tinge, is a common symptom of severe protein deficiency, commonly referred to as Kwashiorkor.&lt;/li&gt;
	&lt;li&gt;Kwashiorkor is more prevalent in areas with limited access to protein-rich foods, such as certain regions in Africa, Central America, and South Asia.&lt;/li&gt;
	&lt;li&gt;Other symptoms of protein deficiency may include muscle wasting, edema, and an enlarged abdomen.&lt;/li&gt;
	&lt;li&gt;A diet rich in legumes, nuts, dairy products, meat, and fish can help prevent protein deficiency.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Kwashiorkor&lt;/strong&gt;:

	&lt;ul&gt;
		&lt;li&gt;A severe form of malnutrition caused by an inadequate intake of protein.&lt;/li&gt;
		&lt;li&gt;Common in children in developing countries where diets are high in carbohydrates but low in protein.&lt;/li&gt;
		&lt;li&gt;Symptoms include edema, irritability, ulcerating dermatoses, and an enlarged liver.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Marasmus&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;Another form of severe malnutrition caused by an overall lack of calories and protein.&lt;/li&gt;
		&lt;li&gt;Characterized by severe wasting of body fat and muscle, leading to a &amp;quot;skin and bones&amp;quot; appearance.&lt;/li&gt;
		&lt;li&gt;Common among children in regions with food scarcity.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Essential Amino Acids&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;Amino acids that the body cannot synthesize on its own and must be obtained from the diet.&lt;/li&gt;
		&lt;li&gt;There are nine essential amino acids: histidine, isoleucine, leucine, lysine, methionine, phenylalanine, threonine, tryptophan, and valine.&lt;/li&gt;
		&lt;li&gt;They are crucial for protein synthesis and other metabolic processes.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Protein-Rich Foods&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;Foods high in protein include meat, fish, eggs, dairy products, legumes, nuts, and seeds.&lt;/li&gt;
		&lt;li&gt;Incorporating a variety of these foods can help ensure adequate protein intake.&lt;/li&gt;
		&lt;li&gt;Plant-based proteins can be combined to provide all essential amino acids, such as rice and beans.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;option 3&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The joint where the neck joins the head is called a pivotal joint. &lt;em&gt;&lt;strong&gt;Hence, option 3 is correct.&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;This joint allows rotation of the head from side to side (left-right movement).&lt;/li&gt;
	&lt;li&gt;It is located between the first cervical vertebra (atlas) and the second cervical vertebra (axis) in the neck.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Saddle joint: &lt;/strong&gt;Found in the thumb (between the metacarpal and carpal bones), allowing movement in two directions.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Hinge joint: &lt;/strong&gt;Found in the knee and elbow, allowing movement in only one direction (like a door hinge).&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Ball and socket joint:&lt;/strong&gt; Found in the shoulder and hip, allowing movement in all directions.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Types of Joints:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Fibrous Joints &amp;rarr; Immovable (e.g., skull sutures)&lt;/li&gt;
		&lt;li&gt;Cartilaginous Joints &amp;rarr; Slightly movable (e.g., vertebrae)&lt;/li&gt;
		&lt;li&gt;Synovial Joints &amp;rarr; Freely movable (main joints for movement)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Examples of Synovial Joints:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Ball and Socket Joint &amp;rarr; Shoulder, Hip &amp;rarr; movement in all directions&lt;/li&gt;
		&lt;li&gt;Hinge Joint &amp;rarr; Elbow, Knee &amp;rarr; bending and straightening&lt;/li&gt;
		&lt;li&gt;Pivot Joint &amp;rarr; Neck (atlas-axis) &amp;rarr; rotation&lt;/li&gt;
		&lt;li&gt;Saddle Joint &amp;rarr; Thumb &amp;rarr; back-and-forth, side-to-side movement&lt;/li&gt;
		&lt;li&gt;Gliding Joint &amp;rarr; Wrist, ankle &amp;rarr; sliding movements&lt;/li&gt;
		&lt;li&gt;Condyloid Joint &amp;rarr; Fingers &amp;rarr; up/down and side/side movement&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Key Features of Synovial Joints:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Synovial cavity filled with synovial fluid &amp;rarr; reduces friction&lt;/li&gt;
		&lt;li&gt;Articular cartilage &amp;rarr; smooth surfaces at bone ends&lt;/li&gt;
		&lt;li&gt;Ligaments &amp;rarr; connect bones and provide stability&lt;/li&gt;
		&lt;li&gt;Muscles and tendons &amp;rarr; enable movement&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;0.25&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Concept:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;b&gt;Mole:&lt;/b&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span&gt;The mole is a unit of measurement for the amount of substance.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span&gt;One mole of any substance contains exactly &lt;span class=&quot;math-tex&quot;&gt;\(6.022 \times 10^{23}\)&lt;/span&gt; entities (this number is known as &lt;b&gt;Avogadro&amp;#39;s number&lt;/b&gt; &lt;span class=&quot;math-tex&quot;&gt;\(N_A\)&lt;/span&gt;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span&gt;Formula to calculate moles: &lt;span class=&quot;math-tex&quot;&gt;\(n = \frac{N}{N_A}\)&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Calculation:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;Given,&lt;/p&gt;

&lt;p&gt;Number of molecules of&lt;span class=&quot;math-tex&quot;&gt;\( CO_2 = N = 1.506 \times 10^{23}\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Avogadro&amp;#39;s number, &lt;span class=&quot;math-tex&quot;&gt;\(N_A = 6.022 \times 10^{23} \, \text{molecules/mol}\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Number of moles of &lt;span class=&quot;math-tex&quot;&gt;\(CO_2\)&lt;/span&gt;,&lt;/p&gt;

&lt;p&gt;&amp;rArr; &lt;span class=&quot;math-tex&quot;&gt;\(n = \frac{N}{N_A}\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr;&lt;span class=&quot;math-tex&quot;&gt;\( n = \frac{1.506 \times 10^{23}}{6.022 \times 10^{23}}\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr;&amp;nbsp;&lt;span class=&quot;math-tex&quot;&gt;\(n \approx 0.25 \ moles\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&amp;there4; The number of moles of&amp;nbsp;&lt;span class=&quot;math-tex&quot;&gt;\( CO_2 \)&lt;/span&gt;&amp;nbsp;present is 0.25.&lt;/strong&gt;&lt;/p&gt;
